import{c as a,Q as o,j as r,m as t}from"./chunks/framework.BXc4yaFE.js";const m=JSON.parse('{"title":"Announcements — claude.com/blog","description":"","frontmatter":{"title":"Announcements — claude.com/blog","type":"index"},"headers":[],"relativePath":"research/claude-blog/announcements/index.md","filePath":"research/claude-blog/announcements/index.md","lastUpdated":1779935873000}'),n={name:"research/claude-blog/announcements/index.md"};function l(i,e,s,u,d,c){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="announcements-—-claude-com-blog" tabindex="-1">Announcements — claude.com/blog <a class="header-anchor" href="#announcements-—-claude-com-blog" aria-label="Permalink to &quot;Announcements — claude.com/blog&quot;">​</a></h1><blockquote><p>收錄自 <a href="https://claude.com/blog/category/announcements" target="_blank" rel="noreferrer">claude.com/blog/category/announcements</a> · 19 篇文章 · 2026-02-17 ~ 2026-05-19 最後更新：2026-05-19</p></blockquote><hr><h2 id="new-in-claude-managed-agents-self-hosted-sandboxes-and-mcp-tunnels" tabindex="-1">New in Claude Managed Agents: self-hosted sandboxes and MCP tunnels <a class="header-anchor" href="#new-in-claude-managed-agents-self-hosted-sandboxes-and-mcp-tunnels" aria-label="Permalink to &quot;New in Claude Managed Agents: self-hosted sandboxes and MCP tunnels&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-19 | <strong>URL:</strong> <a href="https://claude.com/blog/claude-managed-agents-updates" target="_blank" rel="noreferrer">https://claude.com/blog/claude-managed-agents-updates</a></p><h3 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Claude Managed Agents 新增自托管 Sandbox 和 MCP Tunnel 支援，讓 Agent 在企業自控基礎架構內執行工具，同時維持安全與合規。組織可選用 Cloudflare、Daytona、Modal、Vercel 等托管供應商，MCP Tunnel 則允許 Agent 安全存取私有網路服務而無需公開暴露。</p><h3 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>工具執行移至客戶自管環境，Anthropic 基礎架構只負責 Orchestration，敏感檔案與 Repo 留在企業邊界內</li><li>支援 Sandbox 供應商：Cloudflare（microVM + zero-trust secrets）、Daytona（長時 stateful）、Modal（AI 優化 + GPU）、Vercel（毫秒啟動 + VPC peering）</li><li>MCP Tunnel 透過輕量 Gateway（僅需 outbound 連線 + 端對端加密）存取內部 DB、API、服務</li><li>組織可自控資源配置、Runtime Image 和運算容量</li><li>自托管 Sandbox 公開 Beta；MCP Tunnel 為 Research Preview</li></ul><hr><h2 id="claude-for-the-legal-industry" tabindex="-1">Claude for the legal industry <a class="header-anchor" href="#claude-for-the-legal-industry" aria-label="Permalink to &quot;Claude for the legal industry&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-12 | <strong>URL:</strong> <a href="https://claude.com/blog/claude-for-the-legal-industry" target="_blank" rel="noreferrer">https://claude.com/blog/claude-for-the-legal-industry</a></p><h3 id="summary-1" tabindex="-1">Summary <a class="header-anchor" href="#summary-1" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>針對法律專業人士的 20+ MCP Connector 和 12 個實務領域 Plugin 正式發布。整合 iManage、Thomson Reuters、Harvey 等主流法律平台，並深度嵌入 Microsoft Word、Outlook、Excel、PowerPoint。</p><h3 id="key-points-1" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-1" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>20+ MCP Connector：合約（Definely、DocuSign、Ironclad）、文件管理（iManage、NetDocuments）、電子取證（Everlaw、Relativity）、法律研究（Thomson Reuters、Midpage）</li><li>12 個實務領域 Plugin：Commercial、Corporate、Employment、Privacy、IP、Litigation 等</li><li>Microsoft Word 整合：起草和紅線標記；Outlook：來件分類；Cowork：多文件事務</li><li>法律援助診所和非營利組織可透過 Claude for Nonprofits 取得折扣定價</li></ul><hr><h2 id="agent-view-in-claude-code" tabindex="-1">Agent view in Claude Code <a class="header-anchor" href="#agent-view-in-claude-code" aria-label="Permalink to &quot;Agent view in Claude Code&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-11 | <strong>URL:</strong> <a href="https://claude.com/blog/agent-view-in-claude-code" target="_blank" rel="noreferrer">https://claude.com/blog/agent-view-in-claude-code</a></p><h3 id="summary-2" tabindex="-1">Summary <a class="header-anchor" href="#summary-2" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Claude Code 推出 Agent View（Research Preview），統一管理多個並行 Claude Code Session 的介面。可查看所有 Agent 狀態、內嵌互動，以及背景執行管理。</p><h3 id="key-points-2" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-2" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>按左箭頭或執行 <code>claude agents</code> 進入 Agent View</li><li>顯示：Session 狀態、待輸入需求、最後回應、互動時間戳</li><li>內嵌互動：預覽最近幾輪並直接回應，無需進入完整 Session</li><li>背景操作：<code>/bg</code> 命令背景化 Session；<code>claude --bg [task]</code> 直接後台啟動</li><li>適用 Pro、Max、Team、Enterprise 及 Claude API，為 Research Preview</li></ul><hr><h2 id="introducing-the-claude-platform-on-aws" tabindex="-1">Introducing the Claude Platform on AWS <a class="header-anchor" href="#introducing-the-claude-platform-on-aws" aria-label="Permalink to &quot;Introducing the Claude Platform on AWS&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-11 | <strong>URL:</strong> <a href="https://claude.com/blog/claude-platform-on-aws" target="_blank" rel="noreferrer">https://claude.com/blog/claude-platform-on-aws</a></p><h3 id="summary-3" tabindex="-1">Summary <a class="header-anchor" href="#summary-3" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Claude Platform on AWS 正式開放普遍可用（GA）。AWS 客戶可透過 AWS 認證、帳單和承諾整合使用全套 Claude Platform 功能，與 Amazon Bedrock 形成互補選擇。</p><h3 id="key-points-3" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-3" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>包含：Managed Agents（beta）、Advisor（beta）、Web search/fetch、Code execution、Files API、Skills、MCP connector、Prompt caching</li><li>與 Amazon Bedrock 差異：Claude Platform 由 Anthropic 運營（資料在 AWS 邊界外）；Bedrock 由 AWS 處理（嚴格區域駐留需求）</li><li>支援 Opus 4.7、Sonnet 4.6、Haiku 4.5；新版本同步上線</li><li>適用大多數 AWS 商業區域</li></ul><hr><h2 id="collaborate-with-claude-across-excel-powerpoint-word-and-outlook" tabindex="-1">Collaborate with Claude across Excel, PowerPoint, Word and Outlook <a class="header-anchor" href="#collaborate-with-claude-across-excel-powerpoint-word-and-outlook" aria-label="Permalink to &quot;Collaborate with Claude across Excel, PowerPoint, Word and Outlook&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-07 | <strong>URL:</strong> <a href="https://claude.com/blog/collaborate-with-claude-across-excel-powerpoint-word-and-outlook" target="_blank" rel="noreferrer">https://claude.com/blog/collaborate-with-claude-across-excel-powerpoint-word-and-outlook</a></p><h3 id="summary-4" tabindex="-1">Summary <a class="header-anchor" href="#summary-4" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Claude Microsoft 365 Add-in 正式 GA（Excel、PowerPoint、Word），Outlook 進入 Public Beta。跨應用保持完整對話 Context，調整 Excel 假設自動更新 PowerPoint 圖表和 Word 數字。</p><h3 id="key-points-4" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-4" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>跨應用 Context 連續性：在四個 App 間維持完整對話歷史，不需重複背景</li><li>Outlook：郵件分類（依回應優先級）、起草回覆（自動填充收件人/主旨/內容）、行事曆邀請驗證</li><li>企業部署：透過 Microsoft AppSource 管理員中心；OpenTelemetry 整合（Splunk 等）</li><li>Analytics API：提供每用戶、每 App 活動追蹤</li><li>使用中：ServiceNow、Citadel、Bain &amp; Company、Deloitte</li></ul><hr><h2 id="new-in-claude-managed-agents-dreaming-outcomes-and-multiagent-orchestration" tabindex="-1">New in Claude Managed Agents: dreaming, outcomes, and multiagent orchestration <a class="header-anchor" href="#new-in-claude-managed-agents-dreaming-outcomes-and-multiagent-orchestration" aria-label="Permalink to &quot;New in Claude Managed Agents: dreaming, outcomes, and multiagent orchestration&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-06 | <strong>URL:</strong> <a href="https://claude.com/blog/new-in-claude-managed-agents" target="_blank" rel="noreferrer">https://claude.com/blog/new-in-claude-managed-agents</a></p><h3 id="summary-5" tabindex="-1">Summary <a class="header-anchor" href="#summary-5" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Managed Agents 三大新功能：Dreaming（Agent 自主改進）、Outcomes（成功標準定義 + 自校正）、Multiagent Orchestration（主 Agent 委派專業 Agent 並行）。</p><h3 id="key-points-5" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-5" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>Dreaming（Research Preview）：Agent 自動審閱過去 session 和記憶，提取模式並改進；Harvey 跨 session 學習達 6x 更高完成率</li><li>Outcomes（Public Beta）：開發者定義成功評分標準，grader 自動評估輸出；文件生成 +8.4%、簡報 +10.1%</li><li>Multiagent Orchestration（Public Beta）：Lead Agent 委派專業 Agent 並行，共享 filesystem，Claude Console 顯示完整歸因</li><li>Netflix：分析數百次構建日誌找出反覆出現的問題</li></ul><hr><h2 id="higher-usage-limits-for-claude-and-a-compute-deal-with-spacex" tabindex="-1">Higher Usage Limits for Claude and a Compute Deal with SpaceX <a class="header-anchor" href="#higher-usage-limits-for-claude-and-a-compute-deal-with-spacex" aria-label="Permalink to &quot;Higher Usage Limits for Claude and a Compute Deal with SpaceX&quot;">​</a></h2><p><strong>Date:</strong> 2026-05-06 | <strong>URL:</strong> <a href="https://www.anthropic.com/news/higher-limits-spacex" target="_blank" rel="noreferrer">https://www.anthropic.com/news/higher-limits-spacex</a></p><h3 id="summary-6" tabindex="-1">Summary <a class="header-anchor" href="#summary-6" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Anthropic 宣布與 SpaceX 合作取得 300+ MW 算力（22 萬+ NVIDIA GPU），同步提升 Claude Code 速率限制與 Claude Opus API 配額，應對企業客戶合規數據駐留需求與國際擴展需求。</p><h3 id="key-points-6" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-6" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>300+ MW 計算能力：22 萬+ NVIDIA GPU（SpaceX 基礎設施）</li><li>Claude Code 速率限制大幅提升，Opus API 配額同步擴增</li><li>企業合規需求：資料駐留與國際部署支援</li><li>應對高成長需求，預備規模化交付</li></ul><hr><h2 id="claude-for-creative-work" tabindex="-1">Claude for Creative Work <a class="header-anchor" href="#claude-for-creative-work" aria-label="Permalink to &quot;Claude for Creative Work&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-28 | <strong>URL:</strong> <a href="https://www.anthropic.com/news/claude-for-creative-work" target="_blank" rel="noreferrer">https://www.anthropic.com/news/claude-for-creative-work</a></p><h3 id="summary-7" tabindex="-1">Summary <a class="header-anchor" href="#summary-7" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Anthropic 發布與創意軟體工具的整合連接器，創意專業人士可利用 AI 學習複雜軟體、自動化重複任務、跨工具鏈接並加速創意構思。</p><h3 id="key-points-7" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-7" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>新整合：Ableton、Adobe Creative Cloud、Autodesk Fusion、Blender、SketchUp</li><li>用例：學習複雜軟體操作、自動化重複任務、跨工具鏈接</li><li>對象：音樂製作、影像設計、3D 建模、工業設計等創意工作者</li><li>延伸 Connector 生態（現已超過 200 項整合）</li></ul><hr><h2 id="anthropic-names-theo-hourmouzis-gm-of-australia-new-zealand" tabindex="-1">Anthropic Names Theo Hourmouzis GM of Australia &amp; New Zealand <a class="header-anchor" href="#anthropic-names-theo-hourmouzis-gm-of-australia-new-zealand" aria-label="Permalink to &quot;Anthropic Names Theo Hourmouzis GM of Australia &amp; New Zealand&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-27 | <strong>URL:</strong> <a href="https://www.anthropic.com/news/theo-hourmouzis-general-manager-australia-new-zealand" target="_blank" rel="noreferrer">https://www.anthropic.com/news/theo-hourmouzis-general-manager-australia-new-zealand</a></p><h3 id="summary-8" tabindex="-1">Summary <a class="header-anchor" href="#summary-8" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Anthropic 任命 Theo Hourmouzis（前 Snowflake 高管，20+ 年技術領導經驗）為澳洲及紐西蘭總經理，正式開設雪梨辦公室，深化與澳洲企業及學術界合作。</p><h3 id="key-points-8" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-8" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>任命：Theo Hourmouzis，前 Snowflake 高管，20+ 年技術領導資歷</li><li>雪梨辦公室正式開幕（Anthropic 亞太區擴張）</li><li>合作夥伴：Commonwealth Bank、Canva、Xero</li><li>與澳洲大學建立 AI 研究協作</li></ul><hr><h2 id="an-update-on-our-election-safeguards" tabindex="-1">An Update on Our Election Safeguards <a class="header-anchor" href="#an-update-on-our-election-safeguards" aria-label="Permalink to &quot;An Update on Our Election Safeguards&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-24 | <strong>URL:</strong> <a href="https://www.anthropic.com/news/election-safeguards-update" target="_blank" rel="noreferrer">https://www.anthropic.com/news/election-safeguards-update</a></p><h3 id="summary-9" tabindex="-1">Summary <a class="header-anchor" href="#summary-9" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Anthropic 更新選舉資訊保障措施，Claude 政治觀點平衡性評估達 95-96%，有害/合法請求識別準確率達 99.8-100%，並持續建立 600 條選舉提示測試集。</p><h3 id="key-points-9" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-9" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>政治平衡性：95-96% 分數（第三方評估）</li><li>Claude Opus 4.7 有害請求識別：100% 準確率</li><li>Claude Sonnet 合法請求識別：99.8% 準確率</li><li>600 條選舉提示測試集（自動惡意檢測）</li><li>選舉週期後總結報告承諾</li></ul><hr><h2 id="built-in-memory-for-claude-managed-agents" tabindex="-1">Built-in Memory for Claude Managed Agents <a class="header-anchor" href="#built-in-memory-for-claude-managed-agents" aria-label="Permalink to &quot;Built-in Memory for Claude Managed Agents&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-23 | <strong>URL:</strong> <a href="https://claude.com/blog/claude-managed-agents-memory" target="_blank" rel="noreferrer">https://claude.com/blog/claude-managed-agents-memory</a></p><h3 id="summary-10" tabindex="-1">Summary <a class="header-anchor" href="#summary-10" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Managed Agents 推出公開測試版記憶功能，跨 session 持久化學習。採用檔案系統架構直接掛載，原生整合 bash / code execution。</p><h3 id="key-points-10" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-10" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>跨 session 持久化：Agent 累積知識無需手動更新 prompt</li><li>企業控制：權限分層、完整審計紀錄、版本回滾、內容編輯、跨 Agent 共享記憶庫</li><li>API 管理：可匯出記憶、程式化控制、Claude Console 事件追蹤</li><li>驗證結果：Rakuten 97% 首次準確率↑、27% 成本↓；Wisedocs 驗證精度↑30%</li><li>公開 beta 即日可用於所有 Managed Agents 用戶</li></ul><hr><h2 id="new-connectors-in-claude-for-everyday-life" tabindex="-1">New Connectors in Claude for Everyday Life <a class="header-anchor" href="#new-connectors-in-claude-for-everyday-life" aria-label="Permalink to &quot;New Connectors in Claude for Everyday Life&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-23 | <strong>URL:</strong> <a href="https://claude.com/blog/connectors-for-everyday-life" target="_blank" rel="noreferrer">https://claude.com/blog/connectors-for-everyday-life</a></p><h3 id="summary-11" tabindex="-1">Summary <a class="header-anchor" href="#summary-11" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Claude 新增 15 個個人生活應用連接器（餐飲、旅遊、娛樂），整體 Connector 目錄超過 200 項整合。</p><h3 id="key-points-11" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-11" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>新增連接器：Booking.com、Instacart、Spotify、Uber Eats、Resy、StubHub、Audible 等 15 個</li><li>動態建議：根據任務自動推薦適切 Connector</li><li>隱私保護：資料不用於訓練、應用間隔離、用戶購買前必須核准</li><li>無廣告政策；全訂閱方案可用，行動版本 beta</li></ul><hr><h2 id="redesigning-claude-code-on-desktop-for-parallel-agents" tabindex="-1">Redesigning Claude Code on desktop for parallel agents <a class="header-anchor" href="#redesigning-claude-code-on-desktop-for-parallel-agents" aria-label="Permalink to &quot;Redesigning Claude Code on desktop for parallel agents&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-14 | <strong>URL:</strong> <a href="https://claude.com/blog/claude-code-desktop-redesign" target="_blank" rel="noreferrer">https://claude.com/blog/claude-code-desktop-redesign</a></p><blockquote><p>完整摘要見 <a href="./../claude-code/">claude-code/index.md</a></p></blockquote><h3 id="summary-12" tabindex="-1">Summary <a class="header-anchor" href="#summary-12" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>桌面 App 全面重新設計：多 Agent 並行、統一 sidebar、內建終端機和 diff 檢視器。</p><hr><h2 id="introducing-routines-in-claude-code" tabindex="-1">Introducing routines in Claude Code <a class="header-anchor" href="#introducing-routines-in-claude-code" aria-label="Permalink to &quot;Introducing routines in Claude Code&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-14 | <strong>URL:</strong> <a href="https://claude.com/blog/introducing-routines-in-claude-code" target="_blank" rel="noreferrer">https://claude.com/blog/introducing-routines-in-claude-code</a></p><h3 id="summary-13" tabindex="-1">Summary <a class="header-anchor" href="#summary-13" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Routines（Research Preview）：三種自動化執行模式（排程/API/GitHub webhook）。處理重複開發任務，無需手動基礎設施。</p><h3 id="key-points-12" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-12" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>三種執行模式：<strong>Scheduled</strong>（hourly/nightly/weekly）、<strong>API 觸發</strong>（HTTP endpoint）、<strong>Webhook</strong>（GitHub repo 事件）</li><li>使用限額：Pro 每日 5 次、Max 每日 15 次、Team/Enterprise 每日 25 次</li><li>可存取使用者的 repository 和 connector，無需額外 cron job</li></ul><hr><h2 id="the-advisor-strategy-give-agents-an-intelligence-boost" tabindex="-1">The advisor strategy: Give agents an intelligence boost <a class="header-anchor" href="#the-advisor-strategy-give-agents-an-intelligence-boost" aria-label="Permalink to &quot;The advisor strategy: Give agents an intelligence boost&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-09 | <strong>URL:</strong> <a href="https://claude.com/blog/the-advisor-strategy" target="_blank" rel="noreferrer">https://claude.com/blog/the-advisor-strategy</a></p><h3 id="summary-14" tabindex="-1">Summary <a class="header-anchor" href="#summary-14" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Advisor Tool：Opus 作為智慧顧問，Sonnet/Haiku 作為執行者。Haiku + Opus Advisor 可達 BrowseComp 19.7%→41.2%，成本降 85%。一行 API 實作。</p><h3 id="key-points-13" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-13" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>Sonnet + Opus Advisor：SWE-bench Multilingual 提升 2.7 個百分點，成本降 11.9%</li><li>Haiku + Opus Advisor：BrowseComp 從 19.7% 翻倍至 41.2%，成本降 85%</li><li>Advisor tool 作為伺服器端元件整合在單一 API 請求中，一行實作</li><li>Advisor 每次諮詢通常只產生 400-700 個 text token</li></ul><hr><h2 id="making-claude-cowork-ready-for-enterprise" tabindex="-1">Making Claude Cowork ready for enterprise <a class="header-anchor" href="#making-claude-cowork-ready-for-enterprise" aria-label="Permalink to &quot;Making Claude Cowork ready for enterprise&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-09 | <strong>URL:</strong> <a href="https://claude.com/blog/cowork-for-enterprise" target="_blank" rel="noreferrer">https://claude.com/blog/cowork-for-enterprise</a></p><h3 id="summary-15" tabindex="-1">Summary <a class="header-anchor" href="#summary-15" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>企業版 Cowork：RBAC、每團隊預算限制、OpenTelemetry（Splunk 整合）、Zoom MCP connector。</p><h3 id="key-points-14" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-14" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>Organization Controls：管理員管理使用者群組、指派自訂角色</li><li>每團隊預算限制提供可預測的成本監督</li><li>OpenTelemetry 整合支援 Splunk 等 SIEM 管道</li><li>新增 Zoom MCP connector；每工具控制讓管理員限制特定操作</li></ul><hr><h2 id="claude-managed-agents-get-to-production-10x-faster" tabindex="-1">Claude Managed Agents: get to production 10x faster <a class="header-anchor" href="#claude-managed-agents-get-to-production-10x-faster" aria-label="Permalink to &quot;Claude Managed Agents: get to production 10x faster&quot;">​</a></h2><p><strong>Date:</strong> 2026-04-08 | <strong>URL:</strong> <a href="https://claude.com/blog/claude-managed-agents" target="_blank" rel="noreferrer">https://claude.com/blog/claude-managed-agents</a></p><h3 id="summary-16" tabindex="-1">Summary <a class="header-anchor" href="#summary-16" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>雲端託管 Agent API：$0.08/session-hour，10x 更快部署，Public Beta 上線。處理基礎設施複雜性，讓開發者專注於 Agent 邏輯。</p><h3 id="key-points-15" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-15" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>生產就緒功能：長時間 session、多 Agent 協調、範疇化權限、內建執行追蹤</li><li>內部測試：結構化檔案生成任務成功率提升高達 10 個百分點</li><li>消費型定價：標準 Claude token 費率 + 每 session-hour $0.08</li></ul><hr><h2 id="audit-claude-platform-activity-with-the-compliance-api" tabindex="-1">Audit Claude Platform activity with the Compliance API <a class="header-anchor" href="#audit-claude-platform-activity-with-the-compliance-api" aria-label="Permalink to &quot;Audit Claude Platform activity with the Compliance API&quot;">​</a></h2><p><strong>Date:</strong> 2026-03-30 | <strong>URL:</strong> <a href="https://claude.com/blog/claude-platform-compliance-api" target="_blank" rel="noreferrer">https://claude.com/blog/claude-platform-compliance-api</a></p><h3 id="summary-17" tabindex="-1">Summary <a class="header-anchor" href="#summary-17" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Compliance API 讓組織管理員可程序化存取 Claude Platform 部署的審計日誌。追蹤安全相關事件，包括管理操作和資源修改，幫助合規團隊監控使用者活動。</p><h3 id="key-points-16" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-16" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>追蹤兩類活動：管理/系統活動（工作區變更、API 金鑰建立）和資源活動（檔案操作、Skill 管理）</li><li>不記錄推理日誌：專注組織和資源級事件，非直接模型互動</li><li>企業整合：跨 Claude API 和 Enterprise 部署合併活動 feed</li><li>限制：日誌從 API 啟用後開始，無法取得歷史數據</li></ul><hr><h2 id="put-claude-to-work-on-your-computer" tabindex="-1">Put Claude to work on your computer <a class="header-anchor" href="#put-claude-to-work-on-your-computer" aria-label="Permalink to &quot;Put Claude to work on your computer&quot;">​</a></h2><p><strong>Date:</strong> 2026-03-23 | <strong>URL:</strong> <a href="https://claude.com/blog/dispatch-and-computer-use" target="_blank" rel="noreferrer">https://claude.com/blog/dispatch-and-computer-use</a></p><h3 id="summary-18" tabindex="-1">Summary <a class="header-anchor" href="#summary-18" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Claude 在 Cowork 和 Claude Code 中具備電腦使用能力，可控制滑鼠、鍵盤和瀏覽器。Dispatch 讓用戶從手機指派任務，在桌面完成。</p><h3 id="key-points-17" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-17" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>Claude 優先使用直接工具整合，在沒有 connector 時可透過點擊操控螢幕</li><li>包含提示注入偵測和可疑活動掃描安全措施</li><li>Dispatch：跨設備連續對話，從手機指派任務，桌面完成</li><li>適用 Pro 和 Max 訂閱者（macOS 和 Windows），Research Preview</li></ul><hr><h2 id="claude-now-creates-interactive-charts-diagrams-and-visualizations" tabindex="-1">Claude now creates interactive charts, diagrams and visualizations <a class="header-anchor" href="#claude-now-creates-interactive-charts-diagrams-and-visualizations" aria-label="Permalink to &quot;Claude now creates interactive charts, diagrams and visualizations&quot;">​</a></h2><p><strong>Date:</strong> 2026-03-12 | <strong>URL:</strong> <a href="https://claude.com/blog/claude-builds-visuals" target="_blank" rel="noreferrer">https://claude.com/blog/claude-builds-visuals</a></p><h3 id="summary-19" tabindex="-1">Summary <a class="header-anchor" href="#summary-19" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>Claude 現在可以在對話中直接生成互動圖表、圖解和視覺化，無需程式碼。這些內嵌視覺效果作為理解的臨時輔助工具，適用於所有訂閱方案。</p><h3 id="key-points-18" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-18" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>對話中建立：視覺效果內嵌顯示，隨對話演進</li><li>用戶引導或自動：Claude 判斷何時視覺效果有助於解釋</li><li>迭代優化：用戶可在對話中請求調整和深入探索</li><li>適用於所有訂閱層級</li></ul><hr><h2 id="increase-web-search-accuracy-and-efficiency-with-dynamic-filtering" tabindex="-1">Increase web search accuracy and efficiency with dynamic filtering <a class="header-anchor" href="#increase-web-search-accuracy-and-efficiency-with-dynamic-filtering" aria-label="Permalink to &quot;Increase web search accuracy and efficiency with dynamic filtering&quot;">​</a></h2><p><strong>Date:</strong> 2026-02-17 | <strong>URL:</strong> <a href="https://claude.com/blog/improved-web-search-with-dynamic-filtering" target="_blank" rel="noreferrer">https://claude.com/blog/improved-web-search-with-dynamic-filtering</a></p><h3 id="summary-20" tabindex="-1">Summary <a class="header-anchor" href="#summary-20" aria-label="Permalink to &quot;Summary&quot;">​</a></h3><p>更新的 web search 和 web fetch 工具讓 Claude 可自動撰寫並執行程式碼來過濾搜尋結果，提升準確率 11%，同時降低 token 使用量 24%。</p><h3 id="key-points-19" tabindex="-1">Key Points <a class="header-anchor" href="#key-points-19" aria-label="Permalink to &quot;Key Points&quot;">​</a></h3><ul><li>動態過濾技術：Claude 透過程式碼執行過濾不相關的搜尋結果</li><li>基準效能：Sonnet 4.6 BrowseComp 從 33.3% 提升至 46.6%；F1 分數從 52.6% 提升至 59.4%</li><li>Sonnet 4.6 和 Opus 4.6 預設自動啟用（使用新 web search/fetch 工具）</li><li>相關工具：程式碼執行、記憶、程序化工具呼叫、tool search 正式開放</li></ul>',148)])])}const g=a(n,[["render",l]]);export{m as __pageData,g as default};
